"use strict";(self.webpackChunk_servicenow_sdk_docs=self.webpackChunk_servicenow_sdk_docs||[]).push([["451225"],{986452(e){e.exports=JSON.parse('{"tag":{"label":"DataLookup","permalink":"/sdk/tags/data-lookup","allTagsPath":"/sdk/tags","count":2,"items":[{"id":"guides/data-lookup-guide","title":"Data Lookup","description":"Guide for creating ServiceNow Data Lookup definitions (dl_definition) using the Fluent API. A Data Lookup connects a source table to a configurable matcher table and defines which source fields are used to find a matching row and which values are copied back to the source record. In simple terms form field change, record insert, and record update. If you find yourself reaching for a Business Rule (for insert/update) plus a Client Script (for onChange) to implement the same deterministic field-population logic, use Data Lookup instead.","permalink":"/sdk/guides/data-lookup-guide"},{"id":"api/datalookup-api","title":"DataLookup","description":"Creates a Data Lookup definition (dl_definition) that automatically copies field","permalink":"/sdk/api/datalookup-api"}],"unlisted":false}}')}}]);